using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedCategory { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

public class TicketResponse
{
    public required string PredictedCategory { get; set; }
    public required Dictionary<string, float> Confidence { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelTrainer
{
    private static readonly string[] CategoryLabels = ["Billing", "General", "Technical"];

    public static void TrainAndSaveModel(string dataPath, string modelPath, ILogger logger)
    {
        var mlContext = new MLContext(seed: 42);

        // Load data
        var data = mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Split for evaluation (80/20)
        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Build pipeline: featurize text + numeric, then classify
        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Train on training split
        logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on test split
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        logger.LogInformation("=== Model Evaluation Metrics ===");
        logger.LogInformation("  Macro Accuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        logger.LogInformation("  Micro Accuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        logger.LogInformation("  Log Loss:          {LogLoss:F4}", metrics.LogLoss);
        logger.LogInformation("  Log Loss Reduction:{LogLossReduction:F4}", metrics.LogLossReduction);

        foreach (var m in metrics.PerClassLogLoss.Select((value, i) => (value, i)))
        {
            var label = m.i < CategoryLabels.Length ? CategoryLabels[m.i] : $"Class {m.i}";
            logger.LogInformation("  Per-class Log Loss [{Label}]: {LogLoss:F4}", label, m.value);
        }

        // Retrain on full dataset for the production model
        logger.LogInformation("Retraining on full dataset for production model...");
        var productionModel = pipeline.Fit(data);
        mlContext.Model.Save(productionModel, data.Schema, modelPath);
        logger.LogInformation("Model saved to {ModelPath}", modelPath);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController(
    PredictionEnginePool<TicketData, TicketPrediction> predictionPool) : ControllerBase
{
    private static readonly string[] CategoryLabels = ["Billing", "General", "Technical"];

    [HttpPost("predict")]
    public ActionResult<TicketResponse> Predict([FromBody] TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < prediction.Score.Length && i < CategoryLabels.Length; i++)
        {
            confidence[CategoryLabels[i]] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.PredictedCategory,
            Confidence = confidence,
        });
    }
}

